import { Component, h, Prop, Event, EventEmitter, Element, Watch, State, Listen } from '@stencil/core';
import { CloseIcon } from '../../subcomponents/svg/Svg';

@Component({
  tag: 'modal-overlay',
  styleUrl: 'modal-overlay.css',
  shadow: true,
})
export class ModalOverlay {
  @Prop() isopen: boolean = false;
  @Prop() bgColor: string;
 
  @Event() modalClosed: EventEmitter<void>;

  @Element() el: HTMLElement;
  @State() isMobile: boolean = typeof window !== 'undefined' ? window.innerWidth <= 991 : false;
  modalRef?: HTMLDivElement;

  @State() shouldBleedBgColor: boolean = false;
  
  private lastFocusedElement: HTMLElement | null = null;
  private focusableElements: HTMLElement[] = [];

  // Get all focusable elements within the modal
  private getFocusableElements(): HTMLElement[] {
    const focusableSelectors = [
      'a[href]',
      'button:not([disabled])',
      'textarea:not([disabled])',
      'input:not([disabled])',
      'select:not([disabled])',
      '[tabindex]:not([tabindex="-1"])',
      'area[href]',
      'iframe',
      'object',
      'embed',
      '[contenteditable="true"]'
    ].join(', ');

    const allFocusableElements: HTMLElement[] = [];
    const shadowRoot = this.el.shadowRoot;
    
    if (!shadowRoot) return [];

    // Get focusable elements from shadow DOM (including close button)
    const shadowElements = Array.from(shadowRoot.querySelectorAll(focusableSelectors)) as HTMLElement[];
    allFocusableElements.push(...shadowElements);
    
    // Get focusable elements from slotted content
    const slot = shadowRoot.querySelector('slot');
    if (slot) {
      const assignedElements = slot.assignedElements({ flatten: true });
      
      assignedElements.forEach(element => {
        // Check if this element has a shadow root (it's a web component)
        if ((element as any).shadowRoot) {
          const shadowRoot = (element as any).shadowRoot;
          
          // Get focusable elements directly in this shadow root
          const shadowFocusable = shadowRoot.querySelectorAll(focusableSelectors);
          allFocusableElements.push(...Array.from(shadowFocusable) as HTMLElement[]);
          
          // Check for nested web components in the shadow root
          const nestedComponents = shadowRoot.querySelectorAll('*');
          nestedComponents.forEach((nestedEl: any) => {
            if (nestedEl.shadowRoot) {
              const nestedFocusable = nestedEl.shadowRoot.querySelectorAll(focusableSelectors);
              allFocusableElements.push(...Array.from(nestedFocusable) as HTMLElement[]);
              
              // Go one level deeper for deeply nested components
              const deeperComponents = nestedEl.shadowRoot.querySelectorAll('*');
              deeperComponents.forEach((deepEl: any) => {
                if (deepEl.shadowRoot) {
                  const deepFocusable = deepEl.shadowRoot.querySelectorAll(focusableSelectors);
                  allFocusableElements.push(...Array.from(deepFocusable) as HTMLElement[]);
                }
              });
            }
          });
        }
        
        // Check if the element itself is focusable
        if ((element as HTMLElement).matches && (element as HTMLElement).matches(focusableSelectors)) {
          allFocusableElements.push(element as HTMLElement);
        }
        
        // Get all focusable descendants from light DOM
        const descendants = element.querySelectorAll(focusableSelectors);
        allFocusableElements.push(...Array.from(descendants) as HTMLElement[]);
        
        // Check for nested web components in light DOM
        const allElements = element.querySelectorAll('*');
        allElements.forEach(child => {
          if ((child as any).shadowRoot) {
            const shadowFocusable = (child as any).shadowRoot.querySelectorAll(focusableSelectors);
            allFocusableElements.push(...Array.from(shadowFocusable) as HTMLElement[]);
          }
        });
      });
    }

    // Filter out elements that are not visible
    return allFocusableElements.filter(el => {
      const style = window.getComputedStyle(el);
      return style.display !== 'none' && 
             style.visibility !== 'hidden' && 
             (el.offsetParent !== null || el.getClientRects().length > 0);
    });
  }

  // Focus modal when opened
  @Watch('isopen')
  handleIsOpenChange(newValue: boolean) {
    if (newValue) {
      document.body.classList.add('sleep-apnea__modal-open');
      
      // Store the currently focused element
      this.lastFocusedElement = document.activeElement as HTMLElement;
      
      // Set focus to the modal after a brief delay to ensure it's rendered
      setTimeout(() => {
        this.focusableElements = this.getFocusableElements();
        if (this.focusableElements.length > 0) {
          this.focusableElements[0].focus();
        }
      }, 100);
    } else {
      document.body.classList.remove('sleep-apnea__modal-open');
      
      // Restore focus to the previously focused element after a brief delay
      // This allows parent components to set focus if needed
      setTimeout(() => {
        if (this.lastFocusedElement && 
            document.contains(this.lastFocusedElement) &&
            typeof this.lastFocusedElement.focus === 'function') {
          this.lastFocusedElement.focus();
        }
        this.lastFocusedElement = null;
      }, 150);
    }
  }
 
  componentDidLoad() {
    if (this.isopen) {
      document.body.classList.add('sleep-apnea__modal-open');
    }
    window.addEventListener('resize', this.handleResize);
    // Listen for custom event from QnAZepCard and ResultZepCard
    this.el.addEventListener('should-bleed', this.handleShouldBleed);
    this.el.addEventListener('should-unbleed', this.handleShouldUnbleed);
  }
 
  disconnectedCallback() {
    document.body.classList.remove('sleep-apnea__modal-open');
    window.removeEventListener('resize', this.handleResize);
    this.el.removeEventListener('should-bleed', this.handleShouldBleed);
    this.el.removeEventListener('should-unbleed', this.handleShouldUnbleed);
  }

  private handleResize = () => {
    this.isMobile = window.innerWidth <= 991;
  };

  @Listen('keydown', { target: 'window' })
  handleKeyDown(e: KeyboardEvent) {
    if (!this.isopen) return;
    
    if (e.key === 'Escape') {
      this.toggleModal();
      return;
    }

    // Trap focus within modal on Tab key
    if (e.key === 'Tab') {
      // Prevent default and manually manage focus
      e.preventDefault();
      
      this.focusableElements = this.getFocusableElements();
      
      if (this.focusableElements.length === 0) return;

      const firstElement = this.focusableElements[0];
      const lastElement = this.focusableElements[this.focusableElements.length - 1];
      
      // Get active element, checking shadow DOM hierarchy
      let activeElement = document.activeElement;
      
      // If active element is the web component itself, check shadow root
      if (activeElement === this.el && this.el.shadowRoot?.activeElement) {
        activeElement = this.el.shadowRoot.activeElement;
      }
      
      // Check if active element is within any web component's shadow root
      let checkElement = document.activeElement;
      while (checkElement) {
        if ((checkElement as any).shadowRoot?.activeElement) {
          activeElement = (checkElement as any).shadowRoot.activeElement;
          checkElement = activeElement;
        } else {
          break;
        }
      }
      
      // Find current element's position in focusable elements array
      const currentIndex = this.focusableElements.indexOf(activeElement as HTMLElement);

      if (e.shiftKey) {
        // Shift + Tab: moving backwards
        if (currentIndex <= 0) {
          lastElement.focus();
        } else {
          this.focusableElements[currentIndex - 1].focus();
        }
      } else {
        // Tab: moving forwards
        if (currentIndex === -1 || currentIndex >= this.focusableElements.length - 1) {
          firstElement.focus();
        } else {
          this.focusableElements[currentIndex + 1].focus();
        }
      }
    }
  };

  handleShouldBleed = () => {
    this.shouldBleedBgColor = true;
  }

  handleShouldUnbleed = () => {
    this.shouldBleedBgColor = false;
  }
 
  toggleModal = () => {
    document.body.classList.remove('sleep-apnea__modal-open');
    this.modalClosed.emit();
  };
 
  render() {
    return (
      <div>
        <div class={`modal-overlay ${this.isopen ? 'active' : ''}`} id="modalOverlay" aria-hidden={!this.isopen}>
          <button
            type="button"
            class="close-btn"
            id="closeModal"
            onClick={this.toggleModal}
            tabIndex={0}
            onFocus={(e) => {
              (e.target as HTMLButtonElement).setAttribute('aria-hidden', 'false');
            }}
            onBlur={(e) => {
              (e.target as HTMLButtonElement).setAttribute('aria-hidden', 'true');
            }}
            aria-hidden="true"
            aria-label="Close modal"
            style={{ 
              position: 'absolute', 
              top: '45px', 
              right: this.isMobile ? '20px' : '75px', 
              zIndex: '9999' 
            }}
          >
            <CloseIcon className="close-icon" aria-hidden="true" />
          </button>
          <div
            class="modal"
            id="modal"
            role="Quiz dialog"
            aria-modal="true"
            ref={el => (this.modalRef = el as HTMLDivElement)}
            aria-hidden="true"
            style={{ backgroundColor: !this.shouldBleedBgColor ? this.bgColor : 'white' }}
          >
            <div class="modal-content">
              <slot></slot>
            </div>
          </div>
        </div>
      </div>
    );
  }
}